    AND (id LIKE CONCAT('%', #{keyword}, '%')
         OR username LIKE CONCAT('%', #{keyword}, '%'))


    AND status = #{status}


    AND create_time >= #{beginTime}


    AND create_time <= #{endTime}

ORDER BY create_time DESC
